@Override
	public Schema resolve(AnnotatedType type, ModelConverterContext context, Iterator<ModelConverter> chain) {
		JavaType javaType = springDocObjectMapper.jsonMapper().constructType(type.getType());
		if (javaType != null) {
			Class<?> cls = javaType.getRawClass();
			if (modelToSchemaMap.containsKey(cls)) {
				Schema schema = modelToSchemaMap.get(cls);
				if (springDocObjectMapper.isOpenapi31())
					handleSchemaTypes(schema);
				return cloneViaJson(schema, new TypeReference<Schema>() {}, springDocObjectMapper.jsonMapper());
			}
			if (modelToClassMap.containsKey(cls))
				type = new AnnotatedType(modelToClassMap.get(cls)).resolveAsRef(true);
		}
		return (chain.hasNext()) ? chain.next().resolve(type, context, chain) : null;
	}

public void customise(OpenAPI openApi) {
	// Map to store operationId counts
	Map<String, Integer> operationIdCount = new HashMap<>();

	// Iterate through all the paths
	for (Map.Entry<String, PathItem> pathEntry : openApi.getPaths().entrySet()) {
		PathItem pathItem = pathEntry.getValue();

		// Process all HTTP methods for the path (GET, POST, PUT, DELETE, etc.)
		processOperation(pathItem.getGet(), operationIdCount);
		processOperation(pathItem.getPost(), operationIdCount);
		processOperation(pathItem.getPut(), operationIdCount);
		processOperation(pathItem.getDelete(), operationIdCount);
		processOperation(pathItem.getPatch(), operationIdCount);
		processOperation(pathItem.getHead(), operationIdCount);
		processOperation(pathItem.getOptions(), operationIdCount);
		processOperation(pathItem.getTrace(), operationIdCount);
	}
}

public ObjectMapperProvider(SpringDocConfigProperties springDocConfigProperties) {
	this.springDocConfigProperties = springDocConfigProperties;
	OpenApiVersion openApiVersion = springDocConfigProperties.getApiDocs().getVersion();
	if (openApiVersion == OpenApiVersion.OPENAPI_3_1) {
		jsonMapper = Json31.mapper();
		yamlMapper = Yaml31.mapper();
		if (springDocConfigProperties.isUseArbitrarySchemas()) {
			System.setProperty(Schema.USE_ARBITRARY_SCHEMA_PROPERTY, "true");
		}
		if (springDocConfigProperties.isExplicitObjectSchema()) {
			System.setProperty(Schema.EXPLICIT_OBJECT_SCHEMA_PROPERTY, "true");
		}
		else {
			PrimitiveType.explicitObjectType = false;
		}
	}
	else {
		jsonMapper = Json.mapper();
		yamlMapper = Yaml.mapper();
		PrimitiveType.explicitObjectType = null;
	}
}

public void buildTagsFromClass(Class<?> beanType, Set<io.swagger.v3.oas.models.tags.Tag> tags, Set<String> tagsStr, Locale locale) {
	List<Tag> allTags = new ArrayList<>();
	// class tags
	Set<Tags> tagsSet = AnnotatedElementUtils
			.findAllMergedAnnotations(beanType, Tags.class);
	Set<Tag> classTags = tagsSet.stream()
			.flatMap(x -> Stream.of(x.value())).collect(Collectors.toCollection(LinkedHashSet::new));
	classTags.addAll(AnnotatedElementUtils.findAllMergedAnnotations(beanType, Tag.class));
	if (!CollectionUtils.isEmpty(classTags)) {
		tagsStr.addAll(classTags.stream().map(tag -> propertyResolverUtils.resolve(tag.name(), locale)).collect(Collectors.toCollection(LinkedHashSet::new)));
		allTags.addAll(classTags);
		addTags(allTags, tags, locale);
	}
}

public static void handleSchemaTypes(Schema<?> schema) {
	if (schema != null) {
		if (schema.getType() == null && schema.getTypes() == null && schema.get$ref() == null && !isComposedSchema(schema)) {
			schema.addType("object");
		}
		else if (schema.getType() != null && CollectionUtils.isEmpty(schema.getTypes()) && !isComposedSchema(schema)) {
			schema.addType(schema.getType());
		}
		else if (schema.getItems() != null && schema.getItems().getType() != null
				&& CollectionUtils.isEmpty(schema.getItems().getTypes())) {
			schema.getItems().addType(schema.getItems().getType());
		}
		if (schema.getProperties() != null) {
			schema.getProperties().forEach((key, value) -> handleSchemaTypes(value));
		}
		fixNullOnlyAdditionalProperties(schema);
	}
}

public static void fixNullOnlyAdditionalProperties(Schema<?> schema) {
	if (schema == null) {
		return;
	}
	Object additionalProperties = schema.getAdditionalProperties();
	if (additionalProperties instanceof Schema<?> addPropSchema) {
		boolean isNullOnlyType = false;
		Set<String> types = addPropSchema.getTypes();
		if (types != null && types.size() == 1 && types.contains("null")) {
			isNullOnlyType = true;
		}
		else if (types == null && "null".equals(addPropSchema.getType())) {
			isNullOnlyType = true;
		}
		if (isNullOnlyType && addPropSchema.get$ref() == null
				&& addPropSchema.getProperties() == null && addPropSchema.getFormat() == null) {
			addPropSchema.setTypes(null);
			addPropSchema.setType(null);
		}
	}
	if (schema.getProperties() != null) {
		schema.getProperties().values().forEach(prop -> fixNullOnlyAdditionalProperties((Schema<?>) prop));
	}
}

List<String> getInPriorityOrder(Collection<String> classNames) {
	// Initially sort alphabetically
	List<String> alphabeticallyOrderedClassNames = new ArrayList<>(classNames);
	Collections.sort(alphabeticallyOrderedClassNames);
	// Then sort by order
	AutoConfigurationClasses classes = new AutoConfigurationClasses(this.metadataReaderFactory,
			this.autoConfigurationMetadata, alphabeticallyOrderedClassNames);
	List<String> orderedClassNames = new ArrayList<>(classNames);
	Collections.sort(orderedClassNames);
	orderedClassNames.sort((o1, o2) -> {
		int i1 = classes.get(o1).getOrder();
		int i2 = classes.get(o2).getOrder();
		return Integer.compare(i1, i2);
	});
	// Then respect @AutoConfigureBefore @AutoConfigureAfter
	orderedClassNames = sortByAnnotation(classes, orderedClassNames);
	return orderedClassNames;
}

private void logPositiveMatches(StringBuilder message, Map<String, ConditionAndOutcomes> shortOutcomes) {
	message.append(String.format("Positive matches:%n"));
	message.append(String.format("-----------------%n"));
	List<Entry<String, ConditionAndOutcomes>> matched = shortOutcomes.entrySet()
		.stream()
		.filter((entry) -> entry.getValue().isFullMatch())
		.toList();
	if (matched.isEmpty()) {
		message.append(String.format("%n    None%n"));
	}
	else {
		matched.forEach((entry) -> addMatchLogMessage(message, entry.getKey(), entry.getValue()));
	}
	message.append(String.format("%n%n"));
}

private void logNegativeMatches(StringBuilder message, Map<String, ConditionAndOutcomes> shortOutcomes) {
	message.append(String.format("Negative matches:%n"));
	message.append(String.format("-----------------%n"));
	List<Entry<String, ConditionAndOutcomes>> nonMatched = shortOutcomes.entrySet()
		.stream()
		.filter((entry) -> !entry.getValue().isFullMatch())
		.toList();
	if (nonMatched.isEmpty()) {
		message.append(String.format("%n    None%n"));
	}
	else {
		nonMatched.forEach((entry) -> addNonMatchLogMessage(message, entry.getKey(), entry.getValue()));
	}
	message.append(String.format("%n%n"));
}

private Map<ContainerPort, Integer> buildMappingsForNetworkSettings(@Nullable NetworkSettings networkSettings) {
	if (networkSettings == null || CollectionUtils.isEmpty(networkSettings.ports())) {
		return Collections.emptyMap();
	}
	Map<ContainerPort, Integer> mappings = new HashMap<>();
	networkSettings.ports().forEach((containerPortString, hostPorts) -> {
		if (!CollectionUtils.isEmpty(hostPorts)) {
			ContainerPort containerPort = ContainerPort.parse(containerPortString);
			hostPorts.stream()
				.filter(this::isIpV4)
				.forEach((hostPort) -> mappings.put(containerPort, getPortNumber(hostPort)));
		}
	});
	return Collections.unmodifiableMap(mappings);
}

protected void addProperties(Method[] declaredMethods, Field[] declaredFields) {
	@Nullable Method[] methods = new Method[declaredMethods.length];
	for (int i = 0; i < declaredMethods.length; i++) {
		methods[i] = isCandidate(declaredMethods[i]) ? declaredMethods[i] : null;
	}
	for (Method method : methods) {
		addMethodIfPossible(method, "is", 0, BeanProperty::addGetter);
	}
	for (Method method : methods) {
		addMethodIfPossible(method, "get", 0, BeanProperty::addGetter);
	}
	for (Method method : methods) {
		addMethodIfPossible(method, "set", 1, BeanProperty::addSetter);
	}
	for (Field field : declaredFields) {
		addField(field);
	}
}

private int compare(ConfigurationPropertyName n1, ConfigurationPropertyName n2) {
	int l1 = n1.getNumberOfElements();
	int l2 = n2.getNumberOfElements();
	int i1 = 0;
	int i2 = 0;
	while (i1 < l1 || i2 < l2) {
		try {
			ElementType type1 = (i1 < l1) ? n1.elements.getType(i1) : null;
			ElementType type2 = (i2 < l2) ? n2.elements.getType(i2) : null;
			String e1 = (i1 < l1) ? n1.getElement(i1++, Form.UNIFORM) : null;
			String e2 = (i2 < l2) ? n2.getElement(i2++, Form.UNIFORM) : null;
			int result = compare(e1, type1, e2, type2);
			if (result != 0) {
				return result;
			}
		}
		catch (ArrayIndexOutOfBoundsException ex) {
			throw new RuntimeException(ex);
		}
	}
	return 0;
}

private int compare(@Nullable String e1, @Nullable ElementType type1, @Nullable String e2,
			@Nullable ElementType type2) {
		if (e1 == null) {
			return -1;
		}
		if (e2 == null) {
			return 1;
		}
		Assert.state(type1 != null, "'type1' must not be null");
		Assert.state(type2 != null, "'type2' must not be null");
		int result = Boolean.compare(type2.isIndexed(), type1.isIndexed());
		if (result != 0) {
			return result;
		}
		if (type1 == ElementType.NUMERICALLY_INDEXED && type2 == ElementType.NUMERICALLY_INDEXED) {
			long v1 = Long.parseLong(e1);
			long v2 = Long.parseLong(e2);
			return Long.compare(v1, v2);
		}
		return e1.compareTo(e2);
	}

