private List<Schema> findComposedSchemas(String ref, Collection<Schema> schemas) {
	List<Schema> composedSchemas = schemas.stream()
			.filter(ComposedSchema.class::isInstance)
			.map(ComposedSchema.class::cast)
			.filter(s -> s.getAllOf() != null)
			.filter(s -> s.getAllOf().stream().anyMatch(s2 -> ref.equals(s2.get$ref())))
			.map(s -> new Schema().$ref(AnnotationsUtils.COMPONENTS_REF + s.getName()))
			.toList();

	List<Schema> resultSchemas = new ArrayList<>(composedSchemas);

	for (Schema childSchema : composedSchemas) {
		String childSchemaRef = childSchema.get$ref();
		resultSchemas.addAll(findComposedSchemas(childSchemaRef, schemas));
	}

	return resultSchemas;
}

public Schema resolveProperties(Schema schema, Locale locale) {
	resolveProperty(schema::getName, schema::name, propertyResolverUtils, locale);
	resolveProperty(schema::getTitle, schema::title, propertyResolverUtils, locale);
	resolveProperty(schema::getDescription, schema::description, propertyResolverUtils, locale);

	Map<String, Schema> properties = schema.getProperties();
	if (!CollectionUtils.isEmpty(properties)) {
		LinkedHashMap<String, Schema> resolvedSchemas = properties.entrySet().stream().map(es -> {
			es.setValue(resolveProperties(es.getValue(), locale));
			if (es.getValue().getItems() != null) {
				resolveProperties(es.getValue().getItems(), locale);
			}
			return es;
		}).collect(Collectors.toMap(Entry::getKey, Entry::getValue, (e1, e2) -> e2,
				LinkedHashMap::new));
		schema.setProperties(resolvedSchemas);
	}
	return schema;
}

private Set<String> getAnnotationValue(Class<?> annotation) {
	Map<String, @Nullable Object> attributes = getAnnotationMetadata()
		.getAnnotationAttributes(annotation.getName(), true);
	if (attributes == null) {
		return Collections.emptySet();
	}
	Set<String> result = new LinkedHashSet<>();
	String[] value = (String[]) attributes.get("value");
	String[] name = (String[]) attributes.get("name");
	Assert.state(value != null, "'value' must not be null");
	Assert.state(name != null, "'name' must not be null");
	Collections.addAll(result, value);
	Collections.addAll(result, name);
	return result;
}

private Map<String, ConditionAndOutcomes> orderByName(Map<String, ConditionAndOutcomes> outcomes) {
	MultiValueMap<String, String> map = mapToFullyQualifiedNames(outcomes.keySet());
	List<String> shortNames = new ArrayList<>(map.keySet());
	Collections.sort(shortNames);
	Map<String, ConditionAndOutcomes> result = new LinkedHashMap<>();
	for (String shortName : shortNames) {
		List<String> fullyQualifiedNames = map.get(shortName);
		Assert.state(fullyQualifiedNames != null, "'fullyQualifiedNames' must not be null");
		if (fullyQualifiedNames.size() > 1) {
			fullyQualifiedNames
				.forEach((fullyQualifiedName) -> result.put(fullyQualifiedName, outcomes.get(fullyQualifiedName)));
		}
		else {
			result.put(shortName, outcomes.get(fullyQualifiedNames.get(0)));
		}
	}
	return result;
}

private ElementType updateType(ElementType existingType, char ch, int index) {
	if (existingType.isIndexed()) {
		if (existingType == ElementType.NUMERICALLY_INDEXED && !isNumeric(ch)) {
			return ElementType.INDEXED;
		}
		return existingType;
	}
	if (existingType == ElementType.EMPTY && isValidChar(ch, index)) {
		return (index == 0) ? ElementType.UNIFORM : ElementType.NON_UNIFORM;
	}
	if (existingType == ElementType.UNIFORM && ch == '-') {
		return ElementType.DASHED;
	}
	if (!isValidChar(ch, index)) {
		if (existingType == ElementType.EMPTY && !isValidChar(Character.toLowerCase(ch), index)) {
			return ElementType.EMPTY;
		}
		return ElementType.NON_UNIFORM;
	}
	return existingType;
}

