private static int getNestedPropertySeparatorIndex(String propertyPath, boolean last) {
	boolean inKey = false;
	int length = propertyPath.length();
	int i = (last ? length - 1 : 0);
	while (last ? i >= 0 : i < length) {
		switch (propertyPath.charAt(i)) {
			case PropertyAccessor.PROPERTY_KEY_PREFIX_CHAR, PropertyAccessor.PROPERTY_KEY_SUFFIX_CHAR -> {
				inKey = !inKey;
			}
			case PropertyAccessor.NESTED_PROPERTY_SEPARATOR_CHAR -> {
				if (!inKey) {
					return i;
				}
			}
		}
		if (last) {
			i--;
		}
		else {
			i++;
		}
	}
	return -1;
}

private Map<String, Object> parseMapInternal(int nesting, String json) {
	Map<String, Object> map = new LinkedHashMap<>();
	json = trimEdges(json, '{', '}').trim();
	for (String pair : tokenize(json)) {
		String @Nullable [] split = StringUtils.split(pair, ":");
		Assert.state(split != null, () -> "Unable to parse '%s'".formatted(pair));
		@Nullable String[] rawElement = StringUtils.trimArrayElements(split);
		String rawKey = rawElement[0];
		String rawValue = rawElement[1];
		Assert.state(rawKey != null, () -> "rawKey is null in '%s'".formatted(pair));
		Assert.state(rawKey.startsWith("\"") && rawKey.endsWith("\""),
				"Expecting double-quotes around field names");
		String key = trimEdges(rawKey, '"', '"');
		Assert.state(rawValue != null, () -> "rawValue is null in '%s'".formatted(pair));
		Object value = parseInternal(nesting, rawValue);
		map.put(key, value);
	}
	return map;
}

private static List<String> findBetweenBrackets(String value) {
	List<String> collected = new ArrayList<>();
	StringBuilder buffer = new StringBuilder();
	int brackets = 0;
	for (int i = 0; i < value.length(); i++) {
		char c = value.charAt(i);
		if (c == '[') {
			if (brackets > 0) {
				buffer.append(c);
			}
			brackets++;
		}
		else if (c == ']') {
			brackets--;
			if (brackets > 0) {
				buffer.append(c);
			}
			else if (brackets == 0 && !buffer.isEmpty()) {
				collected.add(buffer.toString());
				buffer.setLength(0);
			}
		}
		else if (brackets > 0) {
			buffer.append(c);
		}
	}
	return collected;
}

public static String toDashedForm(String name) {
	StringBuilder result = new StringBuilder(name.length());
	boolean inIndex = false;
	for (int i = 0; i < name.length(); i++) {
		char ch = name.charAt(i);
		if (inIndex) {
			result.append(ch);
			if (ch == ']') {
				inIndex = false;
			}
		}
		else {
			if (ch == '[') {
				inIndex = true;
				result.append(ch);
			}
			else {
				ch = (ch != '_') ? ch : '-';
				if (Character.isUpperCase(ch) && !result.isEmpty() && result.charAt(result.length() - 1) != '-') {
					result.append('-');
				}
				result.append(Character.toLowerCase(ch));
			}
		}
	}
	return result.toString();
}

private static int levenshteinDistance(String s, String t) {
    int sLength = s.length() + 1;
    int tLength = t.length() + 1;

    int[][] distances = new int[tLength][];
    for ( int i = 0; i < tLength; i++ ) {
        distances[i] = new int[sLength];
    }

    for ( int i = 0; i < tLength; i++ ) {
        distances[i][0] = i;
    }
    for ( int i = 0; i < sLength; i++ ) {
        distances[0][i] = i;
    }

    for ( int i = 1; i < tLength; i++ ) {
        for ( int j = 1; j < sLength; j++ ) {
            int cost = s.charAt( j - 1 ) == t.charAt( i - 1 ) ? 0 : 1;
            distances[i][j] = Math.min(
                Math.min(
                    distances[i - 1][j] + 1,
                    distances[i][j - 1] + 1
                ),
                distances[i - 1][j - 1] + cost
            );
        }
    }

    return distances[tLength - 1][sLength - 1];
}

private boolean defaultElementEquals(Elements e1, Elements e2, int i) {
	int l1 = e1.getLength(i);
	int l2 = e2.getLength(i);
	boolean indexed1 = e1.getType(i).isIndexed();
	boolean indexed2 = e2.getType(i).isIndexed();
	int i1 = 0;
	int i2 = 0;
	while (i1 < l1) {
		if (i2 >= l2) {
			return remainderIsNotAlphanumeric(e1, i, i1);
		}
		char ch1 = indexed1 ? e1.charAt(i, i1) : Character.toLowerCase(e1.charAt(i, i1));
		char ch2 = indexed2 ? e2.charAt(i, i2) : Character.toLowerCase(e2.charAt(i, i2));
		if (!indexed1 && !ElementsParser.isAlphaNumeric(ch1)) {
			i1++;
		}
		else if (!indexed2 && !ElementsParser.isAlphaNumeric(ch2)) {
			i2++;
		}
		else if (ch1 != ch2) {
			return false;
		}
		else {
			i1++;
			i2++;
		}
	}
	if (i2 < l2) {
		return remainderIsNotAlphanumeric(e2, i, i2);
	}
	return true;
}

private void writeString(Object value) {
	try {
		this.out.append('"');
		String string = value.toString();
		for (int i = 0; i < string.length(); i++) {
			char ch = string.charAt(i);
			switch (ch) {
				case '"' -> this.out.append("\\\"");
				case '\\' -> this.out.append("\\\\");
				case '\b' -> this.out.append("\\b");
				case '\f' -> this.out.append("\\f");
				case '\n' -> this.out.append("\\n");
				case '\r' -> this.out.append("\\r");
				case '\t' -> this.out.append("\\t");
				default -> {
					if (Character.isISOControl(ch)) {
						this.out.append("\\u");
						this.out.append(String.format("%04X", (int) ch));
					}
					else {
						this.out.append(ch);
					}
				}
			}
		}
		this.out.append('"');
	}
	catch (IOException ex) {
		throw new UncheckedIOException(ex);
	}
}

protected static String getQualifiedName(TypeMirror type) {
    DeclaredType declaredType = type.accept(
        new SimpleTypeVisitor8<DeclaredType, Void>() {
            @Override
            public DeclaredType visitDeclared(DeclaredType t, Void p) {
                return t;
            }
        },
        null
    );

    if ( declaredType == null ) {
        return null;
    }

    TypeElement typeElement = declaredType.asElement().accept(
        new SimpleElementVisitor8<TypeElement, Void>() {
            @Override
            public TypeElement visitType(TypeElement e, Void p) {
                return e;
            }
        },
        null
    );

    return typeElement != null ? typeElement.getQualifiedName().toString() : null;
}
